INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('tymebank', 'TymeBank', 'banking', 81, 'GO', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.tymebank.co.za&size=128', 'https://www.tymebank.co.za', '[{"category":"Compliance","score":"19/20","description":"Fully licensed by SARB PA since 2017, FSP & NCRCP, Banking Assoc member, no major violations."},{"category":"Customer Satisfaction","score":"18/25","description":"Mixed; app ease praised, fraud complaints on Trustpilot/Google; 11M customers."},{"category":"Product Value","score":"30/35","description":"Low/no fees, high savings, transparent, store access strong for low-income."},{"category":"Innovation","score":"9/10","description":"Digital-only cloud, kiosks 3-min onboard, GoalSave, early pay, ID partnership."},{"category":"Customer Support","score":"9/15","description":"Phone/WhatsApp/email; complaints of holds, drops, slow fraud resolution."},{"category":"Accessibility & Security","score":"8/10","description":"App/digital access excellent, kiosks inclusive, POPIA compliant but fraud reports & KYC issues. Encrypted, biometrics."}]'::jsonb, '["no monthly fees","GoalSave 10%+","MoreTyme BNPL","PayShap","kiosks","Visa debit"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: No monthly; ATM R10, card replace R100, decline R3, intl 2% FX","features":""}]'::jsonb, '{"google_play":"4.2/5","ios":"3.5/5"}'::jsonb, '["low fees","innovation","compliance","growth","savings rates","accessibility"]'::jsonb, '["fraud vulnerabilities","support response","app crashes"]'::jsonb, '{"summary":"Praise for UI/fees; complaints fraud/support on reviews/social.","positive_themes":["easy app","no fees","high interest","convenient deposits"],"common_concerns":["fraud/hacks","account holds","slow support"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('capitec-bank', 'Capitec Bank', 'banking', 76, 'GO WITH CAUTION', 'https://www.capitecbank.co.za/globalassets/pages/shared/capitec-logo.svg', 'https://www.capitecbank.co.za', '[{"category":"Compliance","score":"18/20","description":"SARB PA licensed; no 2025/26 major regulatory action; FSCA FSP; POPIA compliant."},{"category":"Customer Satisfaction","score":"20/25","description":"HelloPeter 3.3/5; app Store 4.7/5 with 400K iOS; strong net satisfaction overall."},{"category":"Product Value","score":"28/35","description":"Competitive rates, inclusive low-fee structure, but some fee increases noted 2026."},{"category":"Innovation","score":"8/10","description":"Capitec Connect MVNO, PayShap, Apple Pay, digital-first. Strong fintech moves."},{"category":"Customer Support","score":"7/15","description":"24/7 call centre; branches; complaints of fraud resolution delays, card blocks."},{"category":"Accessibility & Security","score":"6/10","description":"Major app (4.5/5 GP), branches nationwide, but recent data breach/hack incidents and fraud complaints."}]'::jsonb, '["Global One account","Capitec Connect SIM","multi-currency","Apple Pay","PayShap","1% cashback"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: R7/mo fee; ATM R9, card replace R130; Connect SIM from R29","features":""}]'::jsonb, '{"google_play":"4.5/5","ios":"4.7/5"}'::jsonb, '["large customer base","app quality","innovation","low fees","extensive ATM network"]'::jsonb, '["fraud incidents","support delays","fee increases"]'::jsonb, '{"summary":"Mix: app praised, fraud complaints increase. Strong brand loyalty.","positive_themes":["easy banking","great app","cashback"],"common_concerns":["fraud","account frozen","slow support"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('fnb-first-national-bank', 'FNB (First National Bank)', 'banking', 71, 'GO WITH CAUTION', 'https://www.fnb.co.za/images/fnb-logo.svg', 'https://www.fnb.co.za', '[{"category":"Compliance","score":"18/20","description":"SARB PA, FSCA FSP, major bank fully licensed; strong governance & compliance record."},{"category":"Customer Satisfaction","score":"15/25","description":"HelloPeter 2.1/5; iOS 4.7/5; mixed; high complaint volume typical of large banks."},{"category":"Product Value","score":"25/35","description":"Wide range; eBucks rewards strong; fees considered high by some; premium accounts pricey."},{"category":"Innovation","score":"9/10","description":"Nav Money, PayShap, eBucks ecosystem, first SA super app concepts, open banking."},{"category":"Customer Support","score":"8/15","description":"24/7 call, branch, chat; high complaint volumes but resolution exists."},{"category":"Accessibility & Security","score":"7/10","description":"Leading digital access; multiple fraud/phishing incidents; strong app security, but breach exposure."}]'::jsonb, '["eBucks rewards","Nav Money budgeting","multi-product","PayShap","open banking APIs","business banking"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Easy Zero R0/mo; Aspire from R109; Premier from R199; Personal from R275","features":""}]'::jsonb, '{"google_play":"4.4/5","ios":"4.7/5"}'::jsonb, '["eBucks loyalty","innovation","app quality","compliance","wide product range"]'::jsonb, '["high fees","fraud exposure","complex products"]'::jsonb, '{"summary":"eBucks praised; fees and fraud complaints common.","positive_themes":["eBucks","app features","rewards"],"common_concerns":["fraud","high fees","poor call centre"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EX