INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('standard-bank', 'Standard Bank', 'banking', 65, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.standardbank.co.za&size=128', 'https://www.standardbank.co.za', '[{"category":"Compliance","score":"18/20","description":"Major SARB PA bank, FSCA FSP; solid governance; some media coverage on culture issues but no 2025/26 formal sanctions."},{"category":"Customer Satisfaction","score":"12/25","description":"HelloPeter 1.74/5; in-person feedback mixed; app reviews better."},{"category":"Product Value","score":"21/35","description":"Good range but fees average vs Capitec/TymeBank; strong business suite."},{"category":"Innovation","score":"8/10","description":"Shyft FX app, API marketplace, MyMo account, PayShap, open banking."},{"category":"Customer Support","score":"8/15","description":"Large support infrastructure; HelloPeter score suggests resolution gaps."},{"category":"Accessibility & Security","score":"8/10","description":"Nationwide; solid app; POPIA; some phishing/fraud events but robust security controls."}]'::jsonb, '["Shyft forex","MyMo account","API banking","PayShap","business banking","pan-Africa presence"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: MyMo R4.95/mo; Elite R195/mo; Prestige from R149/mo","features":""}]'::jsonb, '{"google_play":"4.2/5","ios":"4.7/5"}'::jsonb, '["pan-Africa coverage","business banking","Shyft app","compliance"]'::jsonb, '["low HelloPeter score","fees","customer service consistency"]'::jsonb, '{"summary":"Business banking praised; retail customer complaints common.","positive_themes":["business solutions","app usability","forex"],"common_concerns":["poor service","fees","fraud"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET na