INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('discovery-bank', 'Discovery Bank', 'banking', 70, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.discovery.co.za&size=128', 'https://www.discovery.co.za/bank', '[{"category":"Compliance","score":"18/20","description":"SARB PA since 2019; FSCA FSP; linked to Discovery group compliance; no major 2025/26 sanctions."},{"category":"Customer Satisfaction","score":"16/25","description":"Strong loyalty from Vitality users; complaints from non-vitality clients; mixed HelloPeter."},{"category":"Product Value","score":"25/35","description":"Dynamic Interest up to 9.75%; Vitality Money rewards strong for health-conscious users; high base fees."},{"category":"Innovation","score":"9/10","description":"Behavioural banking model, Vitality Money integration, real-time rewards, AI-powered insights."},{"category":"Customer Support","score":"6/15","description":"Good in-app; complaints about onboarding and support delays, particularly fraud."},{"category":"Accessibility & Security","score":"6/10","description":"Digital-first; app quality high; POPIA; but requires Discovery ecosystem for best value; some security incidents."}]'::jsonb, '["Vitality Money rewards","Dynamic Interest 9.75%","PayShap","multi-currency","Apple Pay","real-time insights"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Gold from R195/mo; Platinum from R345; Black from R695; linked to Vitality plan","features":""}]'::jsonb, '{"google_play":"4.2/5","ios":"4.5/5"}'::jsonb, '["Vitality integration","high savings rate","innovation","compliance"]'::jsonb, '["high fees for non-Vitality","support gaps","ecosystem lock-in"]'::jsonb, '{"summary":"Vitality users highly positive; non-Vitality see limited value.","positive_themes":["rewards","dynamic interest","innovative"],"common_concerns":["expensive","complex","support delays"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('african-bank', 'African Bank', 'banking', 54, 'NOGO', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.africanbank.co.za&size=128', 'https://www.africanbank.co.za', '[{"category":"Compliance","score":"14/20","description":"SARB PA; emerged from curatorship 2016; current licensing solid but historical issues weigh on score."},{"category":"Customer Satisfaction","score":"9/25","description":"HelloPeter score low; mainly complaints on loan products; savings customers more positive."},{"category":"Product Value","score":"22/35","description":"High savings rates (up to 11%); but loan rates high; limited transactional banking."},{"category":"Innovation","score":"6/10","description":"MyWORLD account; basic digital tools; limited fintech innovation vs peers."},{"category":"Customer Support","score":"6/15","description":"Call centre exists; complaints of difficulty with disputes, slow resolution."},{"category":"Accessibility & Security","score":"5/10","description":"Limited branch network; app basic; security adequate; limited vs Big 4 accessibility."}]'::jsonb, '["MyWORLD multi-pocket account","high savings rates","personal loans","credit cards","fixed deposits"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: MyWORLD R4.95/mo; savings accounts fee-free; loan rates high","features":""}]'::jsonb, '{"google_play":"3.8/5","ios":"3.6/5"}'::jsonb, '["savings rates","compliance recovery","accessible loans"]'::jsonb, '["loan costs","limited features","historical reputation"]'::jsonb, '{"summary":"Savings praised; loan complaints dominant.","positive_themes":["savings interest","account pockets","accessible"],"common_concerns":["loan rates","disputes","service"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('vodacom', 'Vodacom', 'mobile-networks', 63, 'GO WITH CAUTION', 'logos/vodacom.jpg', 'https://www.vodacom.co.za', '[{"category":"Compliance","score":"16/20","description":"ICASA licensed, recent DFA approval; past consumer fine but no major 2025/26 issues."},{"category":"Customer Satisfaction","score":"8/20","description":"HelloPeter 1.18/5 (8,674 reviews, 93% 1-star); app reviews mixed."},{"category":"Product Value","score":"25/30","description":"Competitive data-heavy plans, SIM-only flexibility; recent ~5% hikes."},{"category":"Innovation","score":"8/10","description":"Google Cloud AI partnership, SA first 5G VoNR, VodaPay super app, 5G expansion."},{"category":"Customer Support","score":"7/15","description":"TOBi chat/phone/stores available but frequent complaints on resolution times/expertise."},{"category":"Accessibility & Security","score":"8/10","description":"POPIA/GDPR aligned, zero privacy fines in 2025, disability support (sign language, bundles), proactive PIAs."}]'::jsonb, '["5G network","VodaPay app","fibre/home internet","generous data bundles","eSIM","roaming"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: SIM-only from R129/mo (15GB) to R399/mo (400GB); prepaid R99 (10GB anytime +10GB night owl)","features":""}]'::jsonb, '{"google_play":"4.5/5 (319K reviews) VodaPay","ios":"4.7/5 (149K ratings) VodaPay"}'::jsonb, '["strong network coverage","app quality","innovation","security record","accessibility initiatives"]'::jsonb, '["billing disputes","support delays","low HelloPeter score"]'::jsonb, '{"summary":"Overwhelmingly negative on HelloPeter (billing/service); apps praised for convenience but buggy.","positive_themes":["network reliability","data value","rewards","app convenience"],"common_concerns":["billing errors","poor support","data drain","price hikes"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('telkom-mobile', 'Telkom Mobile', 'mobile-networks', 62, 'GO WITH CAUTION', 'logos/telkom.jpg', 'https://www.telkom.co.za', '[{"category":"Compliance","score":"18/20","description":"ICASA licensed ECS/ECNS, fulfilling USAOs (Thusong centres rollout), no recent fines or major violations."},{"category":"Customer Satisfaction","score":"8/20","description":"Low ratings on HelloPeter/Trustpilot (1.3-1.6/5), complaints on billing/service despite good network availability."},{"category":"Product Value","score":"25/30","description":"Competitive data-heavy plans, Night Surfer bonus, uncapped LTE options, good value vs competitors."},{"category":"Innovation","score":"7/10","description":"Revamped MyTelkom app, data-centric plans (Night Surfer, bundles), 5G expansion, MVNO platform, strong subscriber growth."},{"category":"Customer Support","score":"5/15","description":"Frequent complaints of long waits, unhelpful agents, billing resolution issues."},{"category":"Accessibility & Security","score":"8/10","description":"App biometric login, self-service channels (app, USSD, WhatsApp), 99.1% network availability, POPIA compliant as major operator."}]'::jsonb, '["Prepaid data bundles","LTE/Night Surfer","FreeMe/FlexOn contracts","all-network roaming","MyTelkom app"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Prepaid data R7.50/35MB- R999/100GB; LTE 80GB R169pm; FreeMe from R157/1.5GB; price hikes April 2026","features":""}]'::jsonb, '{"google_play":"4.5/5","ios":"1.3/5"}'::jsonb, '["affordable data pricing","high network availability","rapid subscriber growth","competitive bundles"]'::jsonb, '["billing issues","customer support","contract handling"]'::jsonb, '{"summary":"Mixed-negative: complaints on support/billing outweigh praises for data value.","positive_themes":["cheap data","good coverage","value bundles"],"common_concerns":["billing errors","poor support","contract cancellations","data depletion"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('rain', 'RAIN', 'mobile-networks', 63, 'GO WITH CAUTION', 'logos/rain.jpg', 'https://www.rain.co.za', '[{"category":"Compliance","score":"19/20","description":"ICASA licensed and compliant per 2024/25 report; no fines or violations in 2025/26. Past issues resolved."},{"category":"Customer Satisfaction","score":"10/25","description":"HelloPeter 2.37/5 (6,726 reviews), NPS -54; dominant complaints on service quality despite 100% response rate."},{"category":"Product Value","score":"22/30","description":"Competitive entry pricing and flexibility score well, but low satisfaction impacts perceived value."},{"category":"Innovation","score":"7/10","description":"Pioneered standalone 5G home, bundles with 4G mobile; no standout mobile innovations."},{"category":"Customer Support","score":"8/15","description":"Quick responses but poor resolution rates per reviews; mixed agent experiences."},{"category":"Accessibility & Security","score":"7/10","description":"Standard mobile security with no recent breaches since 2021 minor incident; POPIA compliant terms. Decent but unremarkable."}]'::jsonb, '["month-to-month contracts","4G voice/data/SMS bundles","5G home integration","national coverage"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: From R165/mo rainGO (2GB, 60mins, 100SMS), month-to-month","features":""}]'::jsonb, '{"google_play":"2.81/5 (my rain app, 12k reviews); 4.2/5 (rain talk, 828 reviews)","ios":"No prominent iOS app found"}'::jsonb, '["competitive pricing","ICASA compliance","no contracts","high response rate"]'::jsonb, '["slow speeds","support resolution","outages"]'::jsonb, '{"summary":"HelloPeter 2.37/5 poor; Trustpilot 4.3/5 mixed service focus","positive_themes":["affordable pricing","good agent interactions","reliable for some users"],"common_concerns":["slow speeds","poor support","outages"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('cell-c', 'Cell C', 'mobile-networks', 57, 'NOGO', 'logos/cell-c.jpg', 'https://www.cellc.co.za', '[{"category":"Compliance","score":"14/20","description":"ICASA approved Blue Label ownership transfer Jan 2025; fined R500k by National Consumer Tribunal for CPA violation on roaming overcharges; data breach reported but no POPIA fine noted."},{"category":"Customer Satisfaction","score":"10/20","description":"Low ratings across platforms: Trustpilot 1.7/5, PissedConsumer 1.7/5, app stores mixed; complaints dominate on service failures despite some coverage improvements."},{"category":"Product Value","score":"25/30","description":"Competitive low pricing beats MTN/Vodacom on cost (e.g. cheaper data bundles); good value for budget users but coverage/speed reliant on partners."},{"category":"Innovation","score":"7/10","description":"Asset-light roaming on MTN/Vodacom for LTE coverage; 5G launch imminent 2025; MVNO hosting growth (FNB, Capitec); refreshed app with OTP login, balances; rebranded 2024."},{"category":"Customer Support","score":"6/15","description":"Frequent complaints on unresponsive support, long waits, unhelpful agents, poor resolution (WhatsApp, phone, stores); some positive store experiences."},{"category":"Accessibility & Security","score":"4/10","description":"Recent ransomware data breach exposed customer data; POPIA compliance unconfirmed but incident raises concerns on security practices; app access ok but low ratings suggest usability issues; no specific inclusivity info."}]'::jsonb, '["prepaid/postpaid plans","data bundles","LTE roaming coverage","FTTH fibre","MVNO hosting","device contracts"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Elevate+ from R229/mo (3GB), promos like 20GB R99; 1GB prepaid ~R65","features":""}]'::jsonb, '{"google_play":"3.8/5","ios":"2.7/5"}'::jsonb, '["affordable pricing","improving coverage via partners","MVNO growth","financial turnaround"]'::jsonb, '["billing errors","poor support","data breach"]'::jsonb, '{"summary":"Predominantly negative on reviews sites; complaints on service/billing outweigh positives on price/coverage.","positive_themes":["cheap data","improved network","helpful stores occasionally","value bundles"],"common_concerns":["poor customer service","billing disputes","contract cancellation issues","network outages","data breaches"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('mtn-south-africa', 'MTN South Africa', 'mobile-networks', 50, 'NOGO', 'logos/mtn.jpg', 'https://www.mtn.co.za', '[{"category":"Compliance","score":"16/20","description":"ICASA licensed operator, won 2025 High Court case against flawed ICASA broadband regs, no major fines or license issues in 2025-2026 found."},{"category":"Customer Satisfaction","score":"4/20","description":"HelloPeter 1.14/5 (5k reviews, 94% 1-star), Trustpilot 1.4/5; widespread complaints on service/billing."},{"category":"Product Value","score":"20/30","description":"Competitive plans w/bundles/deals, recent hikes (5.4% avg) but speed increases offset; good value on network perf."},{"category":"Innovation","score":"8/10","description":"Best mobile data network quality SA 2025/26 (9.96 score, top Speedtest 74Mbps); 5G rollout, 3G sunset 2026, MoMo fintech w/Mastercard."},{"category":"Customer Support","score":"4/15","description":"Consistently poor per reviews: long waits, unhelpful agents, endless transfers; channels include app, *135, WhatsApp, stores."},{"category":"Accessibility & Security","score":"6/10","description":"2025 cyber breach exposed some customer data but core financial systems secure; POPIA compliant framework in place, app security average."}]'::jsonb, '["prepaid/postpaid voice/data plans","home LTE/5G uncapped","MoMo mobile money","DataShare","self-service app"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Contracts from R115/mo (30GB), home uncapped from R339/mo (15Mbps); 5.4% hike Feb 2026 w/speed bonuses","features":""}]'::jsonb, '{"google_play":"3.9/5","ios":"~2.5/5"}'::jsonb, '["top network speed/quality","wide coverage","5G adoption","fintech services"]'::jsonb, '["poor customer service","billing disputes","app functionality"]'::jsonb, '{"summary":"Overwhelmingly negative on HelloPeter/Trustpilot re service/billing; positive network mentions.","positive_themes":["network performance","coverage","data speeds"],"common_concerns":["billing errors","poor support","contract cancellations","network outages","data delivery issues"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('workday', 'Workday', 'hr-software', 81, 'GO', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.workday.com&size=128', 'https://www.workday.com', '[{"category":"Compliance","score":"18/20","description":"SOC1/2/3, ISO 27001, GDPR compliant; POPIA tools; no SA fines/reg issues; 94% projects on-time."},{"category":"Customer Satisfaction","score":"18/25","description":"No HelloPeter presence; global Trustpilot shows UX frustration; app reviews mixed-positive; SA adoption strong."},{"category":"Product Value","score":"28/35","description":"High value for enterprises; unified platform but premium pricing + high impl costs."},{"category":"Innovation","score":"9/10","description":"AI Illuminate/Skills Cloud/Copilot; Gartner HCM Leader 10yrs; predictive analytics."},{"category":"Customer Support","score":"11/15","description":"SA office/support line; partner ecosystem (Glyde); mixed global response times."},{"category":"Accessibility & Security","score":"9/10","description":"Strong global security certifications (SOC 2/3, ISO 27001), POPIA support via Evisort CLM, mobile biometric access, no breaches reported in SA."}]'::jsonb, '["unified HCM/payroll","AI analytics","talent management","time tracking","mobile app","compliance tools"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Custom enterprise; est. R1,800-R7,500/emp/year (from $96-504)","features":""}]'::jsonb, '{"google_play":"4.3/5","ios":"4.7/5"}'::jsonb, '["SA presence","AI innovation","scalability","strong security","high adoption"]'::jsonb, '["high enterprise pricing","UI complaints","implementation costs"]'::jsonb, '{"summary":"Positive SA news (780 orgs, partner awards); global UX frustration on Trustpilot; no major SA complaints.","positive_themes":["innovation","reliability","growth","AI features"],"common_concerns":["usability issues","glitches","login problems"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('sage-hr-south-africa', 'Sage HR South Africa', 'hr-software', 85, 'GO', 'https://yt3.googleusercontent.com/bwah0-dqJvfZJ15Zdv8pkn9EqegyDIPeC8x9Ph_ofwHB17jtIALgoUiGEdaN2N2HoERbWcnq=s900-c-k-c0x00ffffff-no-rj', 'https://www.sage.com/en-za/hr', '[{"category":"Compliance","score":"18/20","description":"Established Sage provider with POPIA readiness program. No regulatory issues, fines, or complaints found in SA. Payroll/HR software implies labor law compliance via updates."},{"category":"Customer Satisfaction","score":"21/25","description":"Strong 4.3-4.5/5 on GetApp, Capterra, G2 (300+ reviews). Positive on ease, legislation updates. Limited HelloPeter (1 app complaint). Employee Indeed 4.0/5. No major SA complaints."},{"category":"Product Value","score":"30/35","description":"Modular pricing starts low for SMBs (under R25/emp core), good value with core features + add-ons. Transparent, no contracts, free trial. Covers full HR needs scalably."},{"category":"Innovation","score":"8/10","description":"Cloud platform with mobile app, automation for leave/expenses/performance, legislation auto-updates, self-service. Good for SMBs but no standout 2025/2026 AI/new tech noted."},{"category":"Customer Support","score":"13/15","description":"Phone/email/chat/live Q&A, 24/7 resources. Reviews rate 4.5-4.6/5 responsive; some SA payroll support critiques but overall strong."},{"category":"Accessibility & Security","score":"8/10","description":"Cloud-based access with mobile app for iOS/Android, self-service portal. POPIA compliance efforts ongoing since 2021; no breaches reported. Role-based access implied. Mixed app accessibility feedback."}]'::jsonb, '["leave management","timesheets","shift scheduling","expenses","performance reviews","recruitment"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Core + Leave from R24/emp/mo; add-ons R10-14/emp/mo, Recruitment R1850/mo","features":""}]'::jsonb, '{"google_play":"3.7/5 (Sage Self Service, 501 reviews)","ios":"Limited data; complaints on functionality"}'::jsonb, '["user-friendly","auto legislation compliance","strong support","affordable modular pricing","mobile self-service","integration with Sage Payroll"]'::jsonb, '["mobile app issues","rigid modules","occasional slow dev fixes"]'::jsonb, '{"summary":"Positive in software review sites (4.4+ avg). Limited HelloPeter/Google specific to SA; app complaints minor.","positive_themes":["easy to use","intuitive","great support","time-saving automation","legislation updates"],"common_concerns":["mobile app bugs","shift scheduling tricky","extra security steps slow"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('simplepay', 'SimplePay', 'hr-software', 88, 'GO', 'https://cdn.theorg.com/6838312f-f027-474f-a72a-f7a502c87a4a_medium.jpg', 'https://www.simplepay.co.za', '[{"category":"Compliance","score":"19/20","description":"Auto SARS/DoL compliance (PAYE/UIF/SDL/ETI), eFiling integration, legislative updates, no regulatory issues found."},{"category":"Customer Satisfaction","score":"21/25","description":"Strong ratings on Capterra/Xero (4.5-5/5), praises ease/support/compliance; limited HelloPeter data, low complaints."},{"category":"Product Value","score":"30/35","description":"Single all-features plan, transparent pay-as-you-go, good SME value despite no public prices."},{"category":"Innovation","score":"9/10","description":"Cloud/mobile self-service app, API/Xero integration, auto 2025 updates (e.g. ETI rates)."},{"category":"Customer Support","score":"13/15","description":"Free support praised as quick, knowledgeable, friendly; email/phone channels per reviews."},{"category":"Accessibility & Security","score":"9/10","description":"Strong security with 2FA, role-based access, POPIA statement, ISO 27001 in progress; mobile app ensures accessibility."}]'::jsonb, '["Automated tax/payroll calc","SARS eFiling","leave mgmt","self-service app","Xero/QuickBooks integration","custom items"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: ~R65 base + R18/emp/mo excl VAT","features":""}]'::jsonb, '{"google_play":"N/A (Self-Service app exists, 50K+ downloads)","ios":"N/A"}'::jsonb, '["ease of use","SA compliance","affordability SMEs","strong support","integrations"]'::jsonb, '["complex payrolls","admin pricing"]'::jsonb, '{"summary":"Positive reviews/news; praises ease/compliance/support; minor complex needs complaints.","positive_themes":["simple","compliant","time-savin