INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('just-property', 'Just Property', 'property-letting', 77, 'GO WITH CAUTION', 'https://www.just.property/favicon.ico', 'https://www.justproperty.co.za', '[{"category":"Compliance","score":"18/20","description":"Major SA estate agency with 100+ offices, regulated under PPRA. No major violations found. Established 25+ years."},{"category":"Customer Satisfaction","score":"16/20","description":"Mixed SA reviews: some positive agent service, complaints on HelloPeter/Facebook about deposits/charges at specific branches. Sparse 2025/2026 data."},{"category":"Product Value","score":"28/30","description":"Full rental/sales services with vetting/insurance. Good transparency/value for landlords. Standard industry pricing."},{"category":"Innovation","score":"6/10","description":"Website property search, market insights (2025/2026 articles). No mobile app or advanced digital tools mentioned."},{"category":"Customer Support","score":"12/12","description":"Head office customer experience dept. Claims 24/7 rental management. Positive communication in reviews."},{"category":"Accessibility & Security","score":"8/10","description":"Website accessible online. Assumed POPIA compliance as regulated PPRA estate agency. Offers rental insurance for security. No data breaches reported."}]'::jsonb, '["rental management","tenant vetting","rent collection","maintenance coordination","sales/lettings residential/commercial","RENTSECURE insurance"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Management ~8-12% rent (est.); commissions 5-7.5%+VAT (seller-paid); RENTSECURE 3.5% rent","features":""}]'::jsonb, '{"google_play":"N/A (no app)","ios":"N/A (no app)"}'::jsonb, '["extensive office network","full-service management","long experience","regulated","broad property range"]'::jsonb, '["deposit withholding","unexpected fees","branch inconsistencies"]'::jsonb, '{"summary":"Limited recent SA sentiment; isolated complaints on deposits/charges balance positive service notes.","positive_themes":["professional agents","good communication","comprehensive service","reliable rentals"],"common_concerns":["deposit disputes","extra charges","maintenance fees"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
