 '{"google_play":"N/A (no public app found)","ios":"N/A (internal/enterprise apps only)"}'::jsonb, '["extensive network (135+ offices)","PPRA compliance","professional training academy","tech for agents"]'::jsonb, '["communication issues","service delays","review complaints"]'::jsonb, '{"summary":"Limited recent negative complaints on HelloPeter/Google; no major 2025/2026 scandals; some international poor rental feedback.","positive_themes":["professional service","wide coverage","compliant operations"],"common_concerns":["poor communication","maintenance delays","deposit disputes"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('seeff-property-group', 'Seeff Property Group', 'property-letting', 60, 'GO WITH CAUTION', 'logos/seeff.jpg', 'https://www.seeff.com', '[{"category":"Compliance","score":"18/20","description":"PPRA registered, TPN for tenant screening/evictions, SSLR legal partner. Established 1964, no major 2025/2026 violations."},{"category":"Customer Satisfaction","score":"8/20","description":"Low aggregate ratings: ComplaintsBoard 1.2/5 (35 reviews), HelloPeter ~2.6/5 branches. Frequent letting complaints but some positive Google for sales."},{"category":"Product Value","score":"22/30","description":"Full letting/management services via 200+ offices. Good for hands-off but complaints on execution/value. Transparent market reports. Avg rent ~R9k Q1 2025."},{"category":"Innovation","score":"6/10","description":"Website/virtual tours/PayProp payments/Google Workspace. No app/mobile portal. Early MLS adopter but limited new tech in 2025/6."},{"category":"Customer Support","score":"7/12","description":"200+ offices, phone/email/social. Reviews highlight poor letting support (delays/rudeness) despite network. TPN/SSLR aids evictions/legal. Mixed from reviews."},{"category":"Accessibility & Security","score":"8/10","description":"Website accessible; Google Workspace with enforced 2FA post-incidents. POPIA-compliant per privacy policy. Secure FICA handling, TPN integration. No recent breaches."}]'::jsonb, '["professional photos/virtual tours","multi-platform listings","80k+ email alerts","full management/TPN evictions","SSLR legal support","PayProp automation"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Industry std: 8-12% monthly rent mgmt fee + 50-100% 1st month placement (+VAT); Seeff specifics not public","features":""}]'::jsonb, '{"google_play":"N/A (no app)","ios":"N/A (no app)"}'::jsonb, '["established brand/network","PPRA/TPN compliant","strong marketing","comprehensive letting services"]'::jsonb, '["deposit withholding","inconsistent service","maintenance issues"]'::jsonb, '{"summary":"Negative on HelloPeter/complaints (deposits/maintenance); some positive Google. News neutral-positive market.","positive_themes":["professional marketing","local knowledge (some branches)","smooth processes"],"common_concerns":["deposit disputes","poor maintenance response","rude agents","communication delays"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
