esponse","billing/levy disputes","deposit refunds"]'::jsonb, '{"summary":"Limited recent X activity; HelloPeter mixed-negative recent; historical service awards.","positive_themes":["experience","personal service","transparency","dedicated teams"],"common_concerns":["billing disputes","poor service response","deposit issues"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('rawson-property-letting', 'Rawson Property Letting', 'property-letting', 57, 'NOGO', 'logos/rawson.jpg', 'https://www.rawson.co.za', '[{"category":"Compliance","score":"18/20","description":"Multiple branches registered with PPRA (formerly EAAB), active partner in PPRA transformation initiatives, no 2025/2026 violations found."},{"category":"Customer Satisfaction","score":"8/25","description":"HelloPeter 1.66/5 from 35 recent reviews (83% 1-star), many rental-specific complaints; Google branch ratings mixed 3-5/5."},{"category":"Product Value","score":"22/30","description":"Comprehensive full-service including vetting, payments, maintenance; transparent market-driven pricing aligns with SA norms."},{"category":"Innovation","score":"4/10","description":"Online landlord portal for management, mentions of tech trends/sustainability in 2025 blog, no mobile app or advanced digital features found."},{"category":"Customer Support","score":"6/15","description":"Branch phone/email support, some fast responses noted but frequent complaints of poor communication and maintenance handling in reviews."},{"category":"Accessibility & Security","score":"7/10","description":"Digital portal access available, bank-grade security for payments mentioned on site, PPRA registration implies POPIA compliance, no explicit accessibility features noted."}]'::jsonb, '["tenant vetting & placement","lease management & renewals","maintenance coordination","rent collection & invoicing","property valuations","online portal"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Industry standard ~8% + VAT commission on monthly rental income","features":""}]'::jsonb, '{"google_play":"N/A (no app found)","ios":"N/A (no app found)"}'::jsonb, '["national network","PPRA compliance","full-service rental management","market insights via blog"]'::jsonb, '["deposit withholding","maintenance neglect","agent unprofessionalism"]'::jsonb, '{"summary":"Predominantly negative from HelloPeter/Google reviews (deposits, service); neutral/positive company news/blogs.","positive_themes":["professional service in some cases","market knowledge","transformation efforts"],"common_concerns":["deposit disputes","poor maintenance response","unprofessional agents","communication delays"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
