INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('medshield', 'Medshield', 'medical-aid', 64, 'GO WITH CAUTION', 'https://medshield.co.za/wp-content/uploads/2023/03/blue-logo.png', 'https://www.medshield.co.za', '[{"category":"Compliance","score":"17/20","description":"CMS reg #1140, FSP 51381, AA GCR stable rating; some legacy non-compliance (capitation, assets) but operational and solvent."},{"category":"Customer Satisfaction","score":"8/20","description":"HelloPeter 2.4-2.5 TrustIndex (low), mixed app reviews; some positive testimonials but overall poor."},{"category":"Product Value","score":"25/30","description":"10 plans for various needs, competitive pricing, enhanced limits, network discounts; good value but low satisfaction."},{"category":"Innovation","score":"8/10","description":"Member app (claims/card/auth), virtual GP, WhatsApp channel, CGM/mammograms prevention, SmartCare, Hospital-at-Home."},{"category":"Customer Support","score":"9/15","description":"0860 helpline, WhatsApp, email, app; developer responses to app reviews; complaints on resolution speed."},{"category":"Accessibility & Security","score":"7/10","description":"App and web portal available, virtual care access; POPIA assumed compliant as FSP/CMS but no specific mentions. Secure app data practices noted."}]'::jsonb, '["Unlimited hospital (networks)","virtual GP","prevention screenings (mammogram/eye/CGM)","day-to-day limits/savings","mental health support","gap partnerships"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: From R1,821/mo principal (MediCurve) to R9,489/mo (PremiumPlus); 7.5% 2026 increase","features":""}]'::jsonb, '{"google_play":"N/A (10K+ downloads, updated 2025)","ios":"Mixed (3-4 reviews shown: crashes, auth issues, some praise)"}'::jsonb, '["Affordable plans","strong GCR AA rating","innovative prevention