INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('keyhealth-medical-scheme', 'KeyHealth Medical Scheme', 'medical-aid', 60, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.keyhealth.co.za&size=128', 'https://www.keyhealth.co.za', '[{"category":"Compliance","score":"18/20","description":"CMS registered #1087; no penalties, complaints to CMS possible; standard medical scheme regulation."},{"category":"Customer Satisfaction","score":"8/20","description":"HelloPeter 2.6/5 (65 reviews, 89% 1-star); avg 3.8/5 cited elsewhere; dominant complaints on claims/service."},{"category":"Product Value","score":"25/30","description":"Competitive pricing vs larger schemes, unlimited hospital/PMBs/chronic (26-55), maternity/dental, but DSP req, co-pays non-DSP, limited day-to-day on basic plans."},{"category":"Innovation","score":"5/10","description":"Member app for cards/claims/hospitals/newborn reg (buggy); KEYHEALTH REWARDS, Health Booster, Smart Baby, Easy-ER programs; digital claims/portal."},{"category":"Customer Support","score":"6/15","description":"0860 671 050 (7:30-18:00 Mon-Fri), WhatsApp 0609768319, email; reviews cite unresponsiveness, no callbacks."},{"category":"Accessibility & Security","score":"7/10","description":"App provides digital access to cards/claims/hospitals; collects personal data (not encrypted per Play store); no POPIA breaches or security issues found in searches."}]'::jsonb, '["unlimited hospital (DSP)","PMB/chronic cover","Health Booster screenings","Smart Baby maternity","Easy-ER emergency access","dental/optical benefits"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: From R2187/mo (Essence main) to R13840/mo (Platinum); Gold R8675","features":""}]'::jsonb, '{"google_play":"Not visible (10K+ downloads)","ios":"2.4/5 (524 ratings)"}'::jsonb, '["affordable entry-level plans","transparent no-frills cover","comprehensive hospital/PMB","free add-on programs","95k members"]'::jsonb, '["claim rejections despite auth","unresponsive support","faulty app/portal"]'::jsonb, '{"summary":"HelloPeter low (2.6, claims/service issues); iOS app 2.4/5 (bugs); company testimonials positive; no major X buzz.","positive_themes":["affordable value","good hospital cover when paid","occasional helpful staff"],"common_concerns":["claim denials","poor service response","app bugs","payment suspensions"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('bonitas', 'Bonitas', 'medical-aid', 63, 'GO WITH CAUTION', 'https://cdn.brandfetch.io/id09_HhDWT/w/258/h/100/theme/dark/logo.png', 'https://www.bonitas.co.za', '[{"category":"Compliance","score":"15/20","description":"CMS registered #1512; strong solvency 38.6%; AA+ rating; under CMS s44 forensic investigation for governance/procurement (ongoing 2026 court case with Medscheme), no penalties yet but raises concerns."},{"category":"Customer Satisfaction","score":"10/20","description":"Low ratings: HelloPeter 1.73/5 (Trust Index 4.2), app reviews highlight frustrations despite some positive care stories."},{"category":"Product Value","score":"25/30","description":"Competitive pricing across spectrum, good value in hospital/chronic cover, network savings; some plans loss-making but reserves support."},{"category":"Innovation","score":"7/10","description":"Member app with virtual consults, chat, digital card, wellness tools, authorizations; care programs for chronic/cancer; digital health initiatives."},{"category":"Customer Support","score":"9/15","description":"App chat 8am-8pm Mon-Fri/Sat; phone support; mixed reviews - quick claims praised but frequent complaints on delays/responsiveness."},{"category":"Accessibility & Security","score":"7/10","description":"POPIA compliant with dedicated policy and consent processes; app with digital access but poor usability reports; no known breaches; encrypted data practices in app."}]'::jsonb, '["Hospital plans from R1275","comprehensive up to R12509","chronic 27-60 conditions","network options","digital app","oncology/maternity programs"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: From R1,275/mo (BonCore hospital) to R12,509/mo (BonComprehensive); child rates ~R800-R2500","features":""}]'::jsonb, '{"google_play":"1.9/5","ios":"2.0/5 (est. from reviews)"}'::jsonb, '["Affordable entry plans","strong solvency/reserves","wide plan range","high hospital claims payment speed"]'::jsonb, '["Ongoing regulatory probe","low review ratings","app unreliability"]'::jsonb, '{"summary":"Mixed; positive on financial strength/pricing, negative on service/app from HelloPeter/Google; news focuses on governance disputes.","positive_themes":["affordable pricing","good hospital cover","benefit enhancements","strong financials"],"common_concerns":["claims delays","poor app functionality","customer service response times","governance scrutiny"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('fedhealth', 'Fedhealth', 'medical-aid', 53, 'NOGO', 'https://medicalaidsinsouthafrica.co.za/wp-content/uploads/2012/07/fedhealth_logo.jpg', 'https://www.fedhealth.co.za', '[{"category":"Compliance","score":"18/20","description":"Regulated by CMS under Medical Schemes Act; FSP 18427; GCR AA- rating affirmed 2026 with stable outlook; no major violations reported."},{"category":"Customer Satisfaction","score":"5/20","description":"Very low ratings: HelloPeter 1.27/5 (Trustindex 2.5, 225 recent reviews), Google reviews 1.9/5 (237 reviews); overwhelmingly negative feedback."},{"category":"Product Value","score":"20/30","description":"Competitive pricing for hospital-focused plans with savings options; good entry-level value but co-pays, network limits reduce perceived value; flexible customization."},{"category":"Innovation","score":"6/10","description":"Member app with claims tracking, authorizations, chronic mgmt, real-time notifications; customizable plans, D2D+ benefits; Family Room portal; low app ratings (1.5/5 iOS)."},{"category":"Customer Support","score":"6/15","description":"AI agent Naledi, WhatsApp, phone (85% calls answered in 20s, 88% resolution); complaints highlight unhelpful call centers, delays, poor response quality."},{"category":"Accessibility & Security","score":"6/10","description":"Member app available with biometric login, Family Room portal; POPIA compliance assumed as regulated scheme; low app ratings indicate usability issues but no security breaches reported."}]'::jsonb, '["customizable hospital plans","flexible savings/Threshold","unlimited network GP","chronic benefits (27 PMBs)","maternity/childhood programs","24/7 emergency","DSP pharmacies"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: From R1,155/mo FlexiFED Savvy principal (2026); up to R19,393 Maxima PLUS","features":""}]'::jsonb, '{"google_play":"N/A","ios":"1.5/5"}'::jsonb, '["strong financials (AA- GCR)","affordable entry plans","wide plan range","network access","Sanlam partnership"]'::jsonb, '["claim rejections","service delays","app bugs"]'::jsonb, '{"summary":"Strongly negative on HelloPeter/Google (1.3-1.9/5); complaints dominate claims/service; some positives on coverage.","positive_themes":["hospital coverage","flexible options","chronic support","some positive claims experiences"],"common_concerns":["claim denials","poor service","communication delays","billing errors","coverage gaps"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
