essor issues"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('auto-general', 'Auto & General', 'insurance', 89, 'GO', 'https://mir-s3-cdn-cf.behance.net/project_modules/max_1200_webp/aaa2bd14116249.5627db3d463e3.png', 'https://www.autoandgeneral.co.za', '[{"category":"Compliance","score":"19/20","description":"Long-established SA insurer (since 1985), part of TIH, no negative regulatory findings, assumed fully FSCA licensed with clean track record."},{"category":"Customer Satisfaction","score":"22/25","description":"Excellent HelloPeter rating 4.47/5 (5555 reviews, 81% 5-star, NPS 33), top rankings despite minor complaints."},{"category":"Product Value","score":"30/35","description":"Competitive pricing in line with market, broad product range, value-adds like cashback/legal cover, transparent online quotes."},{"category":"Innovation","score":"9/10","description":"Advanced app with AutoSOS crash detection, roadside tracking, self-inspection, claims submission, biometric security, MyPolicy portal. Top 3 insurer."},{"category":"Customer Support","score":"13/15","description":"100% response rate on reviews (avg 0.14h), phone/app support Mon-Sat, dedicated agents praised."},{"category":"Accessibility & Security","score":"9/10","description":"Biometric app login, POPIA compliance assumed as FSCA licensed insurer. Secure policy management app."}]'::jsonb, '["Comprehensive car/home/business/life cover","AutoSOS app crash detection","roadside/medical assistance","self-inspection","cashback options","legal cover"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Industry avg R800-R1400/mo comprehensive; personalized quotes via quote.autogen.co.za","features":""}]'::jsonb, '{"google_play":"4.0 stars","ios":"4.9 stars"}'::jsonb, '["High customer ratings","innovative app","quick response times","40+ years experience","top industry rankings"]'::jsonb, '["claim processing delays","occasional warranty disputes"]'::jsonb, '{"summary":"Strong positive on HelloPeter/Google Play; active brand presence on social with events/promos; minor complaints balanced by high satisfaction.","positive_themes":["excellent service","quick claims","helpful agents","reliable app"],"common_concerns":["claim delays","warranty issues","poor updates"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
