INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('cleanlab-sa', 'CleanLab SA', 'home-cleaning', 74, 'GO WITH CAUTION', 'https://www.cleanlabsa.co.za/wp-content/uploads/2025/07/Cleanlab-Green-Circle-Icon.png', 'https://www.cleanlab.co.za', '[{"category":"Compliance","score":"16/20","description":"POPIA privacy policy in place; providers vetted, use certified products/equipment. No issues or regulatory violations found for platform type."},{"category":"Customer Satisfaction","score":"18/20","description":"Strong 4.8/5 overall on Rannkly (70 reviews); 4.9/5 Subscriptionbay (69 positive testimonials on professionalism/results); HelloPeter 1/5 (1 review)."},{"category":"Product Value","score":"27/30","description":"Transparent upfront competitive pricing, discounts for loyalty/recurring, broad service range via vetted pros; praised as affordable/good value in reviews."},{"category":"Innovation","score":"6/10","description":"Web platform for instant booking, reviews, management; loyalty discounts. No mobile app."},{"category":"Customer Support","score":"10/12","description":"Real-time support promised; reviews praise responsiveness, easy booking/rescheduling, satisfaction focus."},{"category":"Accessibility & Security","score":"8/10","description":"POPIA-compliant privacy policy with data rights, security measures, secure payments via PayFast; website accessible nationwide. No app or certifications noted."}]'::jsonb, '["vetted providers","online instant booking","transparent pricing","recurring/loyalty plans up to 30% off","nationwide residential/commercial/industrial cleaning/pest/garden","satisfaction guarantee"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Quote-based affordable rates; up to 30% loyalty discounts; no hidden fees","features":""}]'::jsonb, '{"google_play":"N/A","ios":"N/A"}'::jsonb, '["high customer ratings/testimonials","affordable/transparent value","professional vetted services","positive resolution examples"]'::jsonb, '["low HelloPeter rating (1 review)","no published pricing","no app"]'::jsonb, '{"summary":"Overwhelmingly positive on Subscriptionbay/Rannkly (professional, excellent results); 1 negative on HelloPeter; limited broader visibility.","positive_themes":["professionalism","quality results","friendly staff","value for money","easy booking"],"common_concerns":["occasional poor service attitudes","limited review volume on some sites"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
