2026 rates published","features":""}]'::jsonb, '{"google_play":"N/A (no app)","ios":"N/A (no app)"}'::jsonb, '["Insurance & compliance handling","staff vetting","flexible pay-as-you-go","Gauteng-wide service"]'::jsonb, '["No independent reviews","quote-based pricing lacks transparency"]'::jsonb, '{"summary":"No recent mentions on X/Twitter or complaints found; website testimonials positive but dated.","positive_themes":["Reliable staff","thorough cleaning","professional service (from testimonials)"],"common_concerns":["Lack of recent third-party reviews","no public pricing transparency"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('skitterblink', 'Skitterblink', 'home-cleaning', 60, 'GO WITH CAUTION', 'https://cleaningsouthafrica.co.za/wp-content/uploads/2024/06/Skitterblink-Cleaning-Service-Team.webp', 'https://www.skitterblink.co.za', '[{"category":"Compliance","score":"16/20","description":"Established franchise with 25+ years, featured in 2025 industry report; no negative regulatory findings or licensing issues reported."},{"category":"Customer Satisfaction","score":"16/20","description":"Mixed HelloPeter reviews: 3.7/5 overall (15 reviews), 5/5 for Montana branch (14 reviews); recent 2025/2026 reviews show both praise for thoroughness and complaints about service quality."},{"category":"Product Value","score":"24/30","description":"Broad service range including specialized cleaning; value promised via time/money savings but mixed feedback on pricing and quality."},{"category":"Innovation","score":"2/10","description":"No app, digital booking, or tech adoption evident; traditional team-based cleaning services."},{"category":"Customer Support","score":"7/12","description":"Worry-Free Promise offered but complaints about poor response, disappearing after payment, and unresolved issues like broken items."},{"category":"Accessibility & Security","score":"4/10","description":"No app or digital platform; traditional service with no mentions of data security, POPIA compliance, or inclusivity features. Basic website access."}]'::jsonb, '["domestic cleaning","commercial cleaning","trauma & crime scene cleaning","builders clean","carpet/upholstery cleaning","hygiene services"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Not publicly listed; franchise starts from R25,000 per service division; described as affordable but some complaints of high costs","features":""}]'::jsonb, '{"google_play":"N/A","ios":"N/A"}'::jsonb, '["wide service range","trained professional teams","worry-free guarantee","nationwide franchises","25+ years experience"]'::jsonb, '["inconsistent service quality","poor customer response","franchise variability"]'::jsonb, '{"summary":"Mixed HelloPeter (3.7 overall, some branches 5/5), Snupit mixed; recent 2026 reviews include negatives on service/management.","positive_themes":["professional staff","thorough cleaning","reliable teams","efficiency","friendly service"],"common_concerns":["poor communication","incomplete service","high prices","management issues","broken items not replaced"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('mit-mak-motors', 'Mit Mak Motors', 'car-dealers', 91, 'GO', 'https://www.mitmakmotors.co.za/wp-content/uploads/2022/05/Mit-MakLogo.png', 'https://www.mitmak.co.za', '[{"category":"Compliance","score":"18/20","description":"Registered dealer (2015/116638/07); complies with FICA, CPA; past 2017 FIC penalty but 2025 AutoTrader awards show good track record."},{"category":"Customer Satisfaction","score":"23/25","description":"#1 on HelloPeter 4.95/5 (1415 reviews, 96% 5 stars); AutoTrader 4.8/5 (1731); minor social complaints."},{"category":"Product Value","score":"32/35","description":"Competitive used car pricing with full history guarantees; broad range; transparent online listings."},{"category":"Innovation","score":"9/10","description":"Dealership app (iOS), online auction/finance platform, loan calculator."},{"category":"Customer Support","score":"14/15","description":"HelloPeter 100% response, 0.55hr avg, 90 NPS; extended hours; positive feedback."},{"category":"Accessibility & Security","score":"9/10","description":"App claims no data collection; FICA/POPIA compliant via PAIA; no breaches found."}]'::jsonb, '["wide used car range","online finance application","auction platform","nationwide delivery","service history guarantee","test drive booking"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Used cars R130k-R650k (e.g. R240k Polo ~R5k/mo)","features":""}]'::jsonb, '{"google_play":"N/A","ios":"New, insufficient reviews"}'::jsonb, '["top HelloPeter/AutoTrader ratings/awards","fast responsive support","quality guarantees","competitive pricing"]'::jsonb, '["defects in some cars","transparency issues","old FIC penalty"]'::jsonb, '{"summary":"Strongly positive on review sites; some TikTok/FB negatives on defects.","positive_themes":["excellent service","quality vehicles","quick finance","hospitality"],"common_concerns":["vehicle defects","transparency","past compliance issues"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
