al X activity.","positive_themes":["excellent service","quality cars","trustworthy","efficient process"],"common_concerns":["none-prominent","new-company"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('gys-pitzer-motors', 'Gys Pitzer Motors', 'car-dealers', 82, 'GO', 'https://www.gyspitzermotorslindopark.co.za/wp-content/themes/vmg-theme-2025/images/logo.png', 'https://www.gyspitzer.co.za', '[{"category":"Compliance","score":"18/20","description":"6-month CPA warranty standard; POPIA policy on sites; no regulatory complaints or issues found; licensed dealer operating multiple branches."},{"category":"Customer Satisfaction","score":"22/25","description":"HelloPeter 4.95/5 (650 reviews, 96.5% 5 stars recent 2026 praise for staff/service); AutoTrader branches 3.7-4.4/5 (35-44 reviews each) positive recent."},{"category":"Product Value","score":"30/35","description":"Competitive pre-owned pricing, quality sourced vehicles, 6mo warranty good value vs private sale."},{"category":"Innovation","score":"3/10","description":"Basic website showroom; no app/mobile tools/digital booking found; standard industry."},{"category":"Customer Support","score":"13/15","description":"Excellent per reviews: fast, professional staff responses; admin/F&I praised; warranty support implied."},{"category":"Accessibility & Security","score":"8/10","description":"Basic website access; POPIA compliance stated on sites; no advanced security/digital features noted. Standard for dealer."}]'::jsonb, '["pre-owned wide range","competitive prices","6-month CPA warranty","nationwide delivery","multiple Pretoria branches","professional staff"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Pre-owned from R150k (Suzuki) to R800k+ (SUVs/bakkies) 2024/2025 models ZAR","features":""}]'::jsonb, '{"google_play":"N/A","ios":"N/A"}'::jsonb, '["exceptional HelloPeter ratings/volume","consistent positive recent feedback","value pricing/warranty"]'::jsonb, '["minor negative reviews (3%)","branch rating variance"]'::jsonb, '{"summary":"HelloPeter/Google/AutoTrader: highly positive (4.7+ avg weighted), recent 2026 reviews praise service; minimal complaints.","positive_themes":["fast service","friendly/professional staff","hassle-free buying","excellent experience"],"common_concerns":["occasional service delays","low % negative reviews"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('auto-investments-wonderboom', 'Auto Investments Wonderboom', 'car-dealers', 77, 'GO WITH CAUTION', 'https://s3-us-west-2.amazonaws.com/hp-cdn-01/uploads/orgs/auto-investments-wonderboom_logo.jpg', 'https://www.autoinvestments.co.za', '[{"category":"Compliance","score":"18/20","description":"Part of established group with 30+ years; POPIA compliance stated; no negative regulatory news; certified pre-owned vehicles imply NRCS vehicle compliance."},{"category":"Customer Satisfaction","score":"18/20","description":"4.1/5 on AutoTrader (22 reviews); mixed HelloPeter (positive professional service, some dishonest claims); group testimonials mostly positive."},{"category":"Product Value","score":"28/30","description":"Certified pre-owned with inspections; wide range sedans to SUVs; transparent pricing on sites; value via finance and trade-ins."},{"category":"Innovation","score":"5/10","description":"Modern website with vehicle search filters; social media presence (Instagram, TikTok, YouTube); no dedicated app or advanced digital features found."},{"category":"Customer Support","score":"11/12","description":"Positive feedback on sales service, home test drives, follow-up; some complaints on staff attitude; phone, WhatsApp, website contact."},{"category":"Accessibility & Security","score":"8/10","description":"POPIA-compliant privacy policy on group sites with security safeguards; standard website access, no app found."}]'::jsonb, '["certified pre-owned vehicles","finance solutions","home test drives","nationwide group","wide vehicle range","trade-ins"]'::jsonb, '[{"name":"Pricing","cost":"Pricing: Pre-owned cars from R70,000 e.g. Honda Brio; up to R1M+ luxury; finance from R3,000-R12,000 pm (2025/2026 listings)","features":""}]'::jsonb, '{"google_play":"N/A","ios":"N/A"}'::jsonb, '["strong customer service","competitive finance","quality checked cars","convenient processes","positive majority reviews","group backing"]'::jsonb, '["staff rudeness","isolated dishonesty claims"]'::jsonb, '{"summary":"Limited recent X data; website testimonials positive; AutoTrader 4.1/5 mixed but positive leaning.","positive_themes":["professional sales","home test drive convenience","quality finance","good selection"],"common_concerns":["staff attitude issues","isolated dishonesty"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
