tegrated fire/security","rigorous training","ISO accredited"]'::jsonb, '["slow armed response","billing after cancellation","service post-rebrand"]'::jsonb, '{"summary":"Legacy positive on footprint; recent reviews mixed-negative on service. Rebrand 2018. Employee feedback average.","positive_themes":["professional training","national coverage","reliable monitoring"],"common_concerns":["slow response times","billing disputes","poor management"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
