redited","specialised high-risk services","B-BBEE Level 1"]'::jsonb, '["poor service response","rude staff","ineffective theft prevention"]'::jsonb, '{"summary":"HelloPeter poor (3/5, all recent negative); Indeed employee positive (4/5); limited other social/customer data.","positive_themes":["professional training","large workforce","specialised capabilities"],"common_concerns":["arrogant guards","poor response","admin delays","theft despite security"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
