delitySecure low downloads, no rating shown)","ios":"~4/5 (limited reviews)"}'::jsonb, '["PSIRA compliant","largest SA provider (>5000 officers)","national coverage","BEE1","recent expansions/awards"]'::jsonb, '["slow response","billing issues","poor service resolution"]'::jsonb, '{"summary":"Mixed-negative customer reviews on forums/HelloPeter (response/service), positive news on expansions.","positive_themes":["large reliable company","tech features","quick growth"],"common_concerns":["slow response times","poor customer service","billing/cancellation issues"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
