ine convenience"]'::jsonb, '["hidden charges","HelloPeter complaints","billing disputes"]'::jsonb, '{"summary":"Mixed: HelloPeter complaints on charges/service; some positive branch experiences; app mixed.","positive_themes":["easy booking","fleet variety","airport convenience"],"common_concerns":["hidden fees","vehicle condition","support delays"]}'::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
